1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest cases
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (newcomer, 0 years, no prior contract → adds first-insurance 10% per item; we use long-standing 2yr customer second contract? Simplest: just look at base + fee with no modifiers — newcomer with single item has first-insurance. We'll exercise via integration examples)
15	  // Use unmodified single-item with a long-standing customer's follow-up contract so only base + fee + loyalty/follow-up. Simpler: test base premium math via the integration examples already in the spec.
16	
17	  // Base premiums via building-block examples (components, base premium only)
18	  it("2 runes (newcomer, first quote) → premium 60 G (base 50 + 10% first-insurance + 5 fee)", () => {
19	    const result = runScenario({
20	      customer: { yearsWithMHPCO: 0 },
21	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
22	    });
23	    expect(result).toEqual({ results: [{ premium: 60 }] });
24	  });
25	  it("3 runes (newcomer, first quote) → premium 71 G (block 60 + 10% first-insurance + 5 fee)", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
29	    });
30	    expect(result).toEqual({ results: [{ premium: 71 }] });
31	  });
32	  it("4 runes (newcomer, first quote) → premium 115 G (4×25=100 + 10% first-insurance + 5 fee)", () => {
33	    const result = runScenario({
34	      customer: { yearsWithMHPCO: 0 },
35	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
36	    });
37	    expect(result).toEqual({ results: [{ premium: 115 }] });
38	  });
39	  it("7 runes (newcomer, first quote) → premium 198 G (base 175 + 10% = 192.5, +5 fee = 197.5 → 198 rounded up)", () => {
40	    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
41	    const result = runScenario({
42	      customer: { yearsWithMHPCO: 0 },
43	      steps: [{ op: "quote", items }],
44	    });
45	    expect(result).toEqual({ results: [{ premium: 198 }] });
46	  });
47	
48	  // Alike components — clarifying question
49	  it("2 runes + 1 moonstone (newcomer, first quote) → premium 88 G (3×25=75 no block, +10% = 82.5, +5 fee = 87.5 → 88)", () => {
50	    const result = runScenario({
51	      customer: { yearsWithMHPCO: 0 },
52	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
53	    });
54	    expect(result).toEqual({ results: [{ premium: 88 }] });
55	  });
56	  it("3 runes + 3 moonstones (newcomer, first quote) → premium 137 G (two blocks 60+60=120, +10% = 132, +5 fee)", () => {
57	    const result = runScenario({
58	      customer: { yearsWithMHPCO: 0 },
59	      steps: [{
60	        op: "quote",
61	        items: [
62	          { type: "rune" }, { type: "rune" }, { type: "rune" },
63	          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
64	        ],
65	      }],
66	    });
67	    expect(result).toEqual({ results: [{ premium: 137 }] });
68	  });
69	
70	  // Modifier scope on multi-item policies — clarifying question
71	  it("policy: cursed sword + plain amulet (newcomer) → premium 231 G (100+60 base + 50 curse + 16 first-insurance + 5 fee)", () => {
72	    const result = runScenario({
73	      customer: { yearsWithMHPCO: 0 },
74	      steps: [{
75	        op: "quote",
76	        items: [
77	          { type: "sword", cursed: true },
78	          { type: "amulet" },
79	        ],
80	      }],
81	    });
82	    expect(result).toEqual({ results: [{ premium: 231 }] });
83	  });
84	
85	  // Modifier thresholds
86	  it("2-year customer, single sword, first quote → premium 95 G (100 + 10 first-insurance − 20 loyalty + 5 fee)", () => {
87	    const result = runScenario({
88	      customer: { yearsWithMHPCO: 2 },
89	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
90	    });
91	    expect(result).toEqual({ results: [{ premium: 95 }] });
92	  });
93	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies");
94	  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
95	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
96	  it.todo("sword with enchantment 4 and cursed → curse surcharge only");
97	
98	  // Rounding in MHPCO's favor (premium up, payout down)
99	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
100	  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
101	
102	  // Integration examples (premium)
103	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
104	  it.todo("long-standing customer's second contract: cursed sword (steel, enchantment 7), 3 years → premium 160 G");
105	
106	  // Standard claim reimbursement (no special clauses)
107	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full minus 100 deductible)");
108	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");
109	
110	  // High-enchantment claim clause
111	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
112	
113	  // Dragon material clause
114	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full, then deductible)");
115	
116	  // Both clauses — 50% rule wins
117	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
118	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-enchantment then deductible)");
119	
120	  // Deductible per damage event
121	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible once per item)");
122	
123	  // Multiple items of the same type
124	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
125	  it.todo("dragon attack damages both swords → each entry treated as separate damage with its own deductible");
126	  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero, whole claim rejected");
127	
128	  // Cap calculation
129	  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
130	  it.todo("cursed sword premium with modifiers 165 G → cap 2000 G (based on unmodified insurance value)");
131	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
132	
133	  // Cap exhaustion across successive claims
134	  it.todo("sword (cap 2000 G), first claim 1500 G → payout 1400 G, cap remaining 600 G");
135	  it.todo("sword (cap 2000 G), second claim 1500 G → payout 600 G, cap remaining 0 G");
136	
137	  // Edge cases (CLI-level)
138	  it.todo("quote includes unknown item type → CLI exits non-zero, error to stderr, no results to stdout");
139	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero with error");
140	  it.todo("claim with damage amount -200 → CLI exits non-zero with error");
141	});
