1	const PROCESSING_FEE_G = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE_G = 60;
4	const COMPONENT_UNIT_PRICE_G = 25;
5	
6	const MAIN_ITEM_BASE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	
14	type Item = { type: string; cursed?: boolean };
15	type Scenario = {
16	  steps: Array<{ op: "quote"; items: Item[] }>;
17	};
18	
19	const sum = (numbers: number[]): number =>
20	  numbers.reduce((acc, n) => acc + n, 0);
21	
22	const componentBaseForGroup = (count: number): number =>
23	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
24	
25	const componentBaseTotal = (items: Item[]): number => {
26	  const counts = new Map<string, number>();
27	  for (const item of items) {
28	    if (COMPONENT_TYPES.has(item.type)) {
29	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
30	    }
31	  }
32	  return sum([...counts.values()].map(componentBaseForGroup));
33	};
34	
35	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
36	
37	const mainItemModifiers = (item: Item): number =>
38	  item.cursed ? mainItemBase(item) * 0.5 : 0;
39	
40	const firstInsuranceSurcharge = (policyBase: number): number => policyBase / 10;
41	
42	const quotePremium = (items: Item[]): number => {
43	  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
44	  const policyBase = sum(mainItems.map(mainItemBase)) + componentBaseTotal(items);
45	  const itemModifiersTotal = sum(mainItems.map(mainItemModifiers));
46	  return Math.ceil(
47	    policyBase + itemModifiersTotal + firstInsuranceSurcharge(policyBase) + PROCESSING_FEE_G,
48	  );
49	};
50	
51	export const runScenario = (scenario: unknown): unknown => {
52	  const items = (scenario as Scenario).steps[0].items;
53	  return { results: [{ premium: quotePremium(items) }] };
54	};
